import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsNullStringSetWhenNullStringIsNull() throws Exception {
        // Use DEFAULT instance where nullString is null
        CSVFormat format = CSVFormat.DEFAULT;
        // isNullStringSet should return false
        assertFalse(format.isNullStringSet());
    }

    @Test
    void testIsNullStringSetWhenNullStringIsNotNull() throws Exception {
        // Create a CSVFormat with non-null nullString using reflection since withNullString may not exist or be inaccessible
        // or to ensure correctness, create a new instance with nullString set to "NULL"
        // Using reflection to create a CSVFormat instance with nullString = "NULL"
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        CSVFormat format = CSVFormat.DEFAULT;
        // Create a new instance by copying DEFAULT and setting nullString to "NULL"
        // Since CSVFormat is immutable, we use withNullString if available, else reflection

        // Try using withNullString method if exists
        CSVFormat newFormat;
        try {
            newFormat = format.withNullString("NULL");
        } catch (NoSuchMethodError | NoSuchMethodException e) {
            // fallback to reflection clone
            // This fallback is unlikely needed given the provided source
            newFormat = format;
            nullStringField.set(newFormat, "NULL");
        }

        // isNullStringSet should return true
        assertTrue(newFormat.isNullStringSet());
    }
}
